#!/usr/bin/env node
// Captures the two staticrypt assets we need at runtime — the password_template
// HTML and the bundled browser-runtime JS (cryptoEngine + codec + staticryptJs)
// — and writes them as inline string exports into src/staticrypt-assets.generated.ts.
//
// Run when bumping the staticrypt dependency:
//   pnpm --filter @pubsh/core gen:assets
//
// The generated file is committed so that `pnpm install && pnpm build` works
// without re-running this script. Inlining lets us bundle the MCP server into
// a single npm package with no runtime fs reads.

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { createRequire } from "node:module";
import { fileURLToPath } from "node:url";

const require = createRequire(import.meta.url);
const { buildStaticryptJS } = require("staticrypt/cli/helpers.js");

const staticryptPkg = require.resolve("staticrypt/package.json");
const staticryptRoot = dirname(staticryptPkg);
const templatePath = resolve(staticryptRoot, "lib/password_template.html");
const templateHtml = readFileSync(templatePath, "utf8");
const runtimeJs = buildStaticryptJS();

const staticryptVersion = JSON.parse(readFileSync(staticryptPkg, "utf8")).version;

const here = dirname(fileURLToPath(import.meta.url));
const outPath = resolve(here, "..", "src", "staticrypt-assets.generated.ts");

const banner = `// AUTO-GENERATED by scripts/generate-staticrypt-assets.mjs — do not edit by hand.
// Source: staticrypt@${staticryptVersion} (lib/password_template.html + buildStaticryptJS()).
// Regenerate with:  pnpm --filter @pubsh/core gen:assets
`;

const body = `
export const STATICRYPT_VERSION = ${JSON.stringify(staticryptVersion)};

export const STATICRYPT_PASSWORD_TEMPLATE = ${JSON.stringify(templateHtml)};

export const STATICRYPT_RUNTIME_JS = ${JSON.stringify(runtimeJs)};
`;

writeFileSync(outPath, banner + body, "utf8");

const kb = (s) => `${(Buffer.byteLength(s, "utf8") / 1024).toFixed(1)} KiB`;
process.stdout.write(
  `wrote ${outPath}\n  staticrypt: ${staticryptVersion}\n  template: ${kb(templateHtml)}\n  runtime js: ${kb(runtimeJs)}\n`,
);
